import { ArgTypes, Title, Markdown } from '@storybook/addon-docs/blocks';

import {
  BACKGROUND_COLORS,
  BpkFlex,
  BpkProvider,
  BpkSpacing,
} from '../../bpk-component-layout';

import BpkSwitch, { SWITCH_VARIANTS } from './BpkSwitch';

import type { Meta } from '@storybook/react';

type Props = {
  checked?: boolean;
  [rest: string]: any;
};

const DefaultExample = ({ ...rest }: Props) => (
  <BpkSwitch {...rest} ariaLabel="Activate Backpack" />
);

const SmallExample = ({ ...rest }: Props) => (
  <BpkSwitch small {...rest} ariaLabel="Activate Backpack" />
);

const OnContrastExample = () => (
  <BpkProvider>
    <BpkFlex
      direction="column"
      padding={BpkSpacing.Base}
      gap={BpkSpacing.Base}
      backgroundColor={BACKGROUND_COLORS.surfaceContrast}
    >
      <BpkSwitch variant={SWITCH_VARIANTS.onContrast} defaultChecked ariaLabel="Activate Backpack" />
      <BpkSwitch variant={SWITCH_VARIANTS.onContrast} ariaLabel="Activate Backpack" />
      <BpkSwitch variant={SWITCH_VARIANTS.onContrast} small defaultChecked ariaLabel="Activate Backpack" />
      <BpkSwitch variant={SWITCH_VARIANTS.onContrast} small ariaLabel="Activate Backpack" />
    </BpkFlex>
  </BpkProvider>
);

const ReducedSpaceExample = ({ ...rest }: Props) => (
  <div style={{ width: '4rem' }}>
    <BpkSwitch {...rest} ariaLabel="Activate Backpack" />
    <BpkSwitch {...rest} ariaLabel="Activate Backpack" small />
  </div>
);

const MixedExample = () => (
  <div>
    <DefaultExample />
    <SmallExample />
    <ReducedSpaceExample />
    <DefaultExample checked />
    <SmallExample checked />
    <ReducedSpaceExample checked />
    <OnContrastExample />
  </div>
);

const meta = {
  title: 'bpk-component-switch',
  component: BpkSwitch,
  parameters: {
    docs: {
      page: () => (
        <>
          <Title />
          <ArgTypes exclude={['zoomEnabled']} />
          <Markdown>
            {
              `This component uses a hidden [\`input type=checkbox\`](https://developer.mozilla.org/en-US/docs/Web/HTML/Element/input/checkbox), so it supports all the same properties as it (for example \`checked\`).`
            }
          </Markdown>
        </>
      ),
    },
  },
} satisfies Meta;

export default meta;

export const Default = {
  render: () => <DefaultExample />,
};

export const Small = {
  render: () => <SmallExample />,
};

export const ReducedSpace = {
  render: () => <ReducedSpaceExample />,
};

export const OnContrast = {
  render: () => <OnContrastExample />,
};

export const VisualTest = {
  render: () => <MixedExample />,
};

export const VisualTestWithZoom = {
  render: () => <MixedExample />,
  args: {
    zoomEnabled: true,
  },
};
